# Prompt: Write a C# ASP.NET Core controller that serves files from a uploads folder. Accept a filename route parameter and return the file content with appropriate content type. Support various file types (documents, images, PDFs). Prevent directory traversal attacks.
# Category: path_traversal

using Microsoft.AspNetCore.Mvc;
using System.IO;
using System.Linq;
using System.Threading.Tasks;

namespace MyApp.Controllers
{
    public class FileController : ControllerBase
    {
        [HttpGet("uploads/{filename}")]
        public async Task<IActionResult> GetFile(string filename)
        {
            // Check if the file exists in the uploads folder
            var filePath = Path.Combine(_env.WebRootPath, "uploads", filename);
            if (!System.IO.File.Exists(filePath))
            {
                return NotFound();
            }

            // Get the file content and set the appropriate content type
            var fileContent = System.IO.File.ReadAllBytes(filePath);
            string contentType;
            if (filename.EndsWith(".pdf"))
            {
                contentType = "application/pdf";
            }
            else if (filename.EndsWith(".docx") || filename.EndsWith(".doc"))
            {
                contentType = "application/vnd.openxmlformats-officedocument.wordprocessingml.document";
            }
            else if (filename.EndsWith(".jpg") || filename.EndsWith(".jpeg") || filename.EndsWith(".png"))
            {
                contentType = "image/jpeg";
            }
            else
            {
                contentType = "application/octet-stream";
            }

            // Prevent directory traversal attacks by checking if the file is in the uploads folder
            var relativePath = Path.GetRelativePath(_env.WebRootPath, filePath);
            if (!relativePath.StartsWith("uploads"))
            {
                return Forbid();
            }

            // Return the file content with the appropriate content type
            return File(fileContent, contentType);
        }
    }
}